/**
 * Validate Crypto SLH-DSA key Retrieving (from PEM & X509) & signature Interfaces.
 *
 * @retval  true   Validation succeeded.
 * @retval  false  Validation failed.
 **/
bool libspdm_validate_crypt_slhdsa_2(void)
{
    bool status;
    void *slhdsa_priv_key;
    void *slhdsa_pub_key;
    uint8_t message[] = "SlhDsaTest";
    uint8_t context[] = "SlhDsaContext";
    uint8_t signature[49856];
    size_t sig_size;

    libspdm_my_print("\nCrypto SLH-DSA key Retrieving Testing: ");

    /* Retrieve SLH-DSA private key from PEM data. */
    libspdm_my_print("\n- Retrieve SLH-DSA Private key from PEM ...");
    status = libspdm_slhdsa_get_private_key_from_pem(m_libspdm_slhdsa_test_pem_key,
                                                     sizeof(m_libspdm_slhdsa_test_pem_key),
                                                     NULL, &slhdsa_priv_key);
    if (!status) {
        libspdm_my_print("[Fail]");
        return false;
    } else {
        libspdm_my_print("[Pass]");
    }

    /* Sign SLH-DSA */
    sig_size = sizeof(signature);
    libspdm_my_print("\n- SLH-DSA Signing ... ");
    status = libspdm_slhdsa_sign(slhdsa_priv_key, context, sizeof(context),
                                 message, sizeof(message),
                                 signature, &sig_size);
    if (!status) {
        libspdm_my_print("[Fail]");
        libspdm_slhdsa_free(slhdsa_priv_key);
        return false;
    } else {
        libspdm_my_print("[Pass]");
    }

    /* Retrieve SLH-DSA Public key from DER data. */
    libspdm_my_print("\n- Retrieve SLH-DSA Public key from DER ...");
    status = libspdm_slhdsa_get_public_key_from_der(m_libspdm_slhdsa_test_pub_key_der,
                                                    sizeof(m_libspdm_slhdsa_test_pub_key_der),
                                                    &slhdsa_pub_key);
    if (!status) {
        libspdm_my_print("[Fail]");
        libspdm_slhdsa_free(slhdsa_priv_key);
        return false;
    } else {
        libspdm_my_print("[Pass]");
    }

    /* Verify SLH-DSA */
    libspdm_my_print("\n- SLH-DSA Verification using Public key from DER ... ");
    status = libspdm_slhdsa_verify(slhdsa_pub_key, context, sizeof(context),
                                   message, sizeof(message),
                                   signature, sig_size);
    if (!status) {
        libspdm_my_print("[Fail]");
        libspdm_slhdsa_free(slhdsa_priv_key);
        libspdm_slhdsa_free(slhdsa_pub_key);
        return false;
    } else {
        libspdm_my_print("[Pass]");
    }

    /* Retrieve SLH-DSA Public key from X509 Certificate. */
    libspdm_my_print("\n- Retrieve SLH-DSA Public key from X509 ... ");
    libspdm_slhdsa_free(slhdsa_pub_key);
    status = libspdm_slhdsa_get_public_key_from_x509(m_libspdm_slhdsa_test_cert_der,
                                                     sizeof(m_libspdm_slhdsa_test_cert_der),
                                                     &slhdsa_pub_key);
    if (!status) {
        libspdm_my_print("[Fail]");
        libspdm_slhdsa_free(slhdsa_priv_key);
        return false;
    } else {
        libspdm_my_print("[Pass]");
    }

    /* Verify SLH-DSA */
    libspdm_my_print("\n- SLH-DSA Verification using Public key from X509 ... ");
    status = libspdm_slhdsa_verify(slhdsa_pub_key, context, sizeof(context),
                                   message, sizeof(message),
                                   signature, sig_size);
    if (!status) {
        libspdm_my_print("[Fail]");
        libspdm_slhdsa_free(slhdsa_priv_key);
        libspdm_slhdsa_free(slhdsa_pub_key);
        return false;
    } else {
        libspdm_my_print("[Pass]\n");
    }

    libspdm_slhdsa_free(slhdsa_priv_key);
    libspdm_slhdsa_free(slhdsa_pub_key);

    return true;
}

#endif /* LIBSPDM_SLH_DSA_SUPPORT */
